          var mdText = rawElement.value;
          renderedElement.innerHTML = marked.parse(mdText);
        }

        setTimeout(updateIframeHeight, 100);
      });

      function toggleCollapsible() {
        var collapsible = document.getElementById('sakuraCollapsible');
        var header = collapsible.querySelector('.sakura-header');
        var isExpanded = collapsible.classList.toggle('expanded');
        header.setAttribute('aria-expanded', isExpanded ? 'true' : 'false');

        if (isExpanded) {
          triggerPetalFall();
        }

        setTimeout(updateIframeHeight, 50);
        setTimeout(updateIframeHeight, 550);
      }

      function triggerPetalFall() {
        var contentBox = document.querySelector('.sakura-content-wrapper');
        var petalCount = 8;
        var emojis = ['🌸', '💮'];

        for (var i = 0; i < petalCount; i++) {
          var petal = document.createElement('div');
          petal.className = 'petal-particle';
          petal.innerText = emojis[Math.floor(Math.random() * emojis.length)];

          var size = 10 + Math.random() * 8;
          var startX = 10 + Math.random() * 80;
          var duration = 1.5 + Math.random() * 1.5;
          var delay = Math.random() * 0.5;

          petal.style.fontSize = size + 'px';
          petal.style.left = startX + '%';
          petal.style.animationDuration = duration + 's';
          petal.style.animationDelay = delay + 's';

          contentBox.appendChild(petal);

          (function(el, parent, t) {
            setTimeout(function() {
              if (el.parentNode === parent) parent.removeChild(el);
            }, t);
          })(petal, contentBox, (duration + delay) * 1000);
        }
      }

      function updateIframeHeight() {
        var bodyHeight = document.body.scrollHeight;
        if (window.parent && window.parent !== window) {
          window.parent.postMessage({ type: 'resizeIframe', height: bodyHeight }, '*');
        }
      }

      document.addEventListener('keydown', function (event) {
        if (event.key === 'Enter' || event.key === ' ') {
          var activeElement = document.activeElement;
          if (activeElement && activeElement.classList.contains('sakura-header')) {
            event.preventDefault();
            toggleCollapsible();
          }
        }
      });

      window.addEventListener('load', updateIframeHeight);
      window.addEventListener('resize', updateIframeHeight);
    </script>
