    /* 收起：从中部滑出到左侧 (用 closing 类暂时改变 transition 参数) */
    .sakura-collapsible.closing .stripe {
      transform: translateX(-85vw) skewX(-28deg);
      opacity: 0;
      transition-timing-function: cubic-bezier(0.55, 0, 1, 0.45);
