    .sakura-collapsible.closing .stripe-white {
      transition-duration: 0.5s;
      transition-delay: 0.06s;
    }

    .sakura-collapsible.closing .stripe-lightpink {
      transition-duration: 0.5s;
      transition-delay: 0.03s;
    }

    .sakura-collapsible.closing .stripe-pink {
      transition-duration: 0.5s;
      transition-delay: 0s;
