    /* ========== Options Inner ========== */
    .options-inner {
      padding: 18px;
      color: #555;
      line-height: 1.65;
      font-size: 14px;
      position: relative;
      word-break: break-word;
      max-height: 360px;
      overflow-y: auto;
      z-index: 2;
      opacity: 0;
      transform: translateY(-8px);
      transition: opacity 0.5s cubic-bezier(0.25, 1, 0.5, 1) 0.1s,
                  transform 0.5s cubic-bezier(0.25, 1, 0.5, 1) 0.1s;
    }

    .sakura-collapsible.expanded .options-inner {
      opacity: 1;
      transform: translateY(0);
    }

    .options-inner::-webkit-scrollbar { width: 6px; }
    .options-inner::-webkit-scrollbar-track { background: transparent; }
    .options-inner::-webkit-scrollbar-thumb { background: #ffc2ce; border-radius: 3px; }

    /* ========== Action Buttons ========== */
    .polar-actions-container {
      display: flex;
      flex-direction: column;
      gap: 10px;
    }

    .polar-action-btn {
      display: flex;
      align-items: flex-start;
      background: rgba(255, 255, 255, 0.55);
      border: 1px solid rgba(255, 182, 193, 0.45);
      border-radius: 12px;
      padding: 12px 14px;
      cursor: pointer;
      transition: all 0.35s cubic-bezier(0.25, 1, 0.5, 1);
      position: relative;
      overflow: hidden;
      transform: translateZ(0);
    }

    @supports (backdrop-filter: blur(1px)) {
      .polar-action-btn {
        -webkit-backdrop-filter: blur(8px);
        backdrop-filter: blur(8px);
      }
    }

    @supports not (backdrop-filter: blur(1px)) {
      .polar-action-btn {
        background: rgba(255, 255, 255, 0.85);
      }
    }

    .polar-action-btn:hover {
      background: rgba(255, 240, 245, 0.8);
      border-color: #ffb7c5;
      transform: translateX(4px) translateZ(0);
      box-shadow: 0 4px 14px rgba(255, 145, 164, 0.12);
    }

    .action-idx {
      font-family: 'Times New Roman', serif;
      font-style: italic;
      color: #d14c77;
      margin-right: 14px;
      font-weight: bold;
      flex-shrink: 0;
      transition: color 0.3s, text-shadow 0.3s;
      min-width: 28px;
      font-size: 15px;
    }

    .polar-action-btn:hover .action-idx {
      color: #ff7b9c;
